import{_ as o,o as i,c as a,ak as l}from"./chunks/framework.Dpc0wyhY.js";const h=JSON.parse('{"title":"Messages","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/messaging/messages.md","filePath":"grindr-api/messaging/messages.md"}'),t={name:"grindr-api/messaging/messages.md"};function d(s,e,n,c,r,u){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to “Messages”">​</a></h1><h2 id="message" tabindex="-1">Message <a class="header-anchor" href="#message" aria-label="Permalink to “Message”">​</a></h2><ul><li><code>messageId</code> — string, appears to be a unix timestamp in milliseconds and UUIDv4 separated by <code>:</code>, e.g. <code>&quot;1774296692000:843daee8-1e93-47d6-bc7f-3d981925a393&quot;</code></li><li><code>conversationId</code> — string, see <a href="/grindr-api/messaging/conversations#conversation">Conversation</a></li><li><code>senderId</code> — number</li><li><code>timestamp</code> — unix timestamp in milliseconds, appears to be same as in <code>messageId</code></li><li><code>unsent</code> — boolean, if this is true, <code>body</code> is set to <code>null</code></li><li><code>reactions</code> — array of objects <ul><li><code>profileId</code> — integer</li><li><code>reactionType</code> — integer (<code>1</code> is &quot;🔥&quot;)</li></ul></li><li><code>type</code> — string, see <a href="#message-type">Message type</a></li><li><code>body</code> — object with <a href="#message-contents">Message contents</a></li><li><code>replyToMessage</code> — unknown or <code>null</code></li><li><code>dynamic</code> — boolean, unknown purpose, WIP</li><li><code>chat1Type</code> — string, see <a href="#message-type">Message type</a></li><li><code>replyPreview</code> — unknown or <code>null</code></li></ul><h2 id="message-type" tabindex="-1">Message type <a class="header-anchor" href="#message-type" aria-label="Permalink to “Message type”">​</a></h2><ul><li><code>&quot;Album&quot;</code></li><li><code>&quot;AlbumContentReaction&quot;</code></li><li><code>&quot;AlbumContentReply&quot;</code></li><li><code>&quot;Audio&quot;</code></li><li><code>&quot;ExpiringAlbum&quot;</code></li><li><code>&quot;ExpiringAlbumV2&quot;</code></li><li><code>&quot;ExpiringImage&quot;</code></li><li><code>&quot;Video&quot;</code></li><li><code>&quot;Gaymoji&quot;</code></li><li><code>&quot;Generative&quot;</code></li><li><code>&quot;Giphy&quot;</code></li><li><code>&quot;Image&quot;</code></li><li><code>&quot;Location&quot;</code></li><li><code>&quot;PrivateVideo&quot;</code></li><li><code>&quot;ProfileLink&quot;</code></li><li><code>&quot;ProfilePhotoReply&quot;</code></li><li><code>&quot;Retract&quot;</code></li><li><code>&quot;Text&quot;</code></li><li><code>&quot;Unknown&quot;</code></li><li><code>&quot;NonExpiringVideo&quot;</code></li><li><code>&quot;VideoCall&quot;</code></li></ul><p>There also appears to be a related <code>chat1Type</code>, could be legacy type.</p><p>Possible values:</p><ul><li><code>&quot;map&quot;</code></li><li><code>&quot;image&quot;</code></li><li><code>&quot;expiring_album&quot;</code></li><li><code>&quot;expiring_image&quot;</code></li><li><code>&quot;private_video&quot;</code></li><li><code>&quot;expiring_video&quot;</code></li><li><code>&quot;gaymoji&quot;</code></li><li><code>&quot;giphy&quot;</code></li><li><code>&quot;audio&quot;</code></li><li><code>&quot;video_call&quot;</code></li><li><code>&quot;video_call_v3&quot;</code></li><li><code>&quot;audio_call&quot;</code></li><li><code>&quot;text&quot;</code></li><li><code>&quot;unknown&quot;</code></li><li><code>&quot;retracted&quot;</code></li><li><code>&quot;retracted_location&quot;</code></li><li><code>&quot;album_share&quot;</code></li><li><code>&quot;album_react&quot;</code></li><li><code>&quot;album_content_reaction&quot;</code></li><li><code>&quot;album_content_reply&quot;</code></li></ul><h2 id="message-contents" tabindex="-1">Message contents <a class="header-anchor" href="#message-contents" aria-label="Permalink to “Message contents”">​</a></h2><p>Payload in <a href="#message"><code>body</code></a> based on <a href="#message-type">message&#39;s <code>type</code></a>, might be <code>null</code> for <a href="#unsend-a-message">unsent</a> messages.</p><h3 id="album" tabindex="-1"><code>&quot;Album&quot;</code> <a class="header-anchor" href="#album" aria-label="Permalink to “&quot;Album&quot;”">​</a></h3><ul><li><em>everything from <a href="/grindr-api/messaging/albums#albumpreview">AlbumPreview</a></em></li><li><em>everything from <a href="/grindr-api/messaging/albums#albumexpiration">AlbumExpiration</a></em></li><li><code>coverUrl</code> — <a href="/grindr-api/messaging/albums#albumcoverurl">AlbumCoverUrl</a></li><li><code>ownerProfileId</code> — number or <code>null</code> if album has expired or was locked</li><li><code>isViewable</code> — boolean</li><li><code>hasVideo</code> — boolean</li><li><code>hasPhoto</code> — boolean</li><li><code>viewableUntil</code> — number or <code>null</code></li></ul><h3 id="expiringalbum" tabindex="-1"><code>&quot;ExpiringAlbum&quot;</code> <a class="header-anchor" href="#expiringalbum" aria-label="Permalink to “&quot;ExpiringAlbum&quot;”">​</a></h3><ul><li><em>everything from <a href="#album">&quot;Album&quot; message type</a></em></li></ul><h3 id="expiringalbumv2" tabindex="-1"><code>&quot;ExpiringAlbumV2&quot;</code> <a class="header-anchor" href="#expiringalbumv2" aria-label="Permalink to “&quot;ExpiringAlbumV2&quot;”">​</a></h3><p>For <a href="/grindr-api/messaging/albums#albumexpirationtype">AlbumExpirationType</a> = <code>ONCE</code> but might have other values if expiration settings were changed later.</p><ul><li><em>everything from <a href="#expiringalbum">&quot;ExpiringAlbum&quot; message type</a></em></li></ul><h3 id="albumcontentreaction" tabindex="-1"><code>&quot;AlbumContentReaction&quot;</code> <a class="header-anchor" href="#albumcontentreaction" aria-label="Permalink to “&quot;AlbumContentReaction&quot;”">​</a></h3><p>Implies &quot;🔥&quot; reaction as there does not appear to be any choice.</p><ul><li><code>albumId</code> — integer</li><li><code>ownerProfileId</code> — integer or <code>null</code> if album has expired or was locked</li><li><code>albumContentId</code> — integer</li><li><code>previewUrl</code> — string or <code>null</code> if album has expired or was locked, see <a href="/grindr-api/media/signed-cdn-files#chat-media">Signed CDN files -&gt; Chat media</a></li><li><code>expiresAt</code> — unix timestamp in milliseconds or <code>null</code></li><li><code>viewable</code> — boolean</li></ul><h3 id="albumcontentreply" tabindex="-1"><code>&quot;AlbumContentReply&quot;</code> <a class="header-anchor" href="#albumcontentreply" aria-label="Permalink to “&quot;AlbumContentReply&quot;”">​</a></h3><ul><li><em>everything from <a href="#albumcontentreaction">&quot;AlbumContentReaction&quot; message type</a></em></li><li><code>albumContentReply</code> — string</li><li><code>contentType</code> — string or <code>null</code> if album has expired or was locked</li></ul><h3 id="audio" tabindex="-1"><code>&quot;Audio&quot;</code> <a class="header-anchor" href="#audio" aria-label="Permalink to “&quot;Audio&quot;”">​</a></h3><ul><li><code>mediaId</code> — number</li><li><code>mediaHash</code> — string or <code>null</code></li><li><code>url</code> — string, see <a href="/grindr-api/media/signed-cdn-files#chat-media">Signed CDN files -&gt; Chat media</a></li><li><code>contentType</code> — string, e.g. <code>audio/aac</code></li><li><code>length</code> — number in milliseconds (1/1000th of a second) or <code>null</code></li><li><code>expiresAt</code> — unix timestamp in milliseconds, 15 minutes</li></ul><h3 id="video" tabindex="-1"><code>&quot;Video&quot;</code> <a class="header-anchor" href="#video" aria-label="Permalink to “&quot;Video&quot;”">​</a></h3><ul><li><code>mediaId</code> — number or <code>null</code></li><li><code>url</code> — string or <code>null</code></li><li><code>fileCacheKey</code> — string</li><li><code>contentType</code> — string or <code>null</code></li><li><code>length</code> — number</li><li><code>maxViews</code> — integer or <code>null</code></li><li><code>looping</code> — boolean or <code>null</code></li></ul><p>Additionally, for expiring videos:</p><ul><li><code>viewsRemaining</code> — integer, capped at <code>2147483647</code> for &quot;unlimited&quot; views</li></ul><h3 id="privatevideo" tabindex="-1"><code>&quot;PrivateVideo&quot;</code> <a class="header-anchor" href="#privatevideo" aria-label="Permalink to “&quot;PrivateVideo&quot;”">​</a></h3><ul><li><em>everything from <a href="#video">&quot;Video&quot; message type</a></em></li><li><code>viewCount</code> — integer</li></ul><h3 id="nonexpiringvideo" tabindex="-1"><code>&quot;NonExpiringVideo&quot;</code> <a class="header-anchor" href="#nonexpiringvideo" aria-label="Permalink to “&quot;NonExpiringVideo&quot;”">​</a></h3><p>Unknown, WIP</p><h3 id="gaymoji" tabindex="-1"><code>&quot;Gaymoji&quot;</code> <a class="header-anchor" href="#gaymoji" aria-label="Permalink to “&quot;Gaymoji&quot;”">​</a></h3><ul><li><code>imageHash</code> — string</li></ul><h3 id="generative" tabindex="-1"><code>&quot;Generative&quot;</code> <a class="header-anchor" href="#generative" aria-label="Permalink to “&quot;Generative&quot;”">​</a></h3><p>Unknown, WIP</p><h3 id="giphy" tabindex="-1"><code>&quot;Giphy&quot;</code> <a class="header-anchor" href="#giphy" aria-label="Permalink to “&quot;Giphy&quot;”">​</a></h3><p>URLs point at <code>https://media0.giphy.com</code></p><ul><li><code>id</code> — string</li><li><code>urlPath</code> — string, full URL to gif file</li><li><code>stillPath</code> — string, single frame, URL to gif file</li><li><code>previewPath</code> — string</li><li><code>width</code> — integer</li><li><code>height</code> — integer</li><li><code>imageHash</code> — string</li></ul><h3 id="image" tabindex="-1"><code>&quot;Image&quot;</code> <a class="header-anchor" href="#image" aria-label="Permalink to “&quot;Image&quot;”">​</a></h3><ul><li><code>mediaId</code> — number</li><li><code>url</code> — string</li><li><code>width</code> — integer or <code>null</code></li><li><code>height</code> — integer or <code>null</code></li><li><code>imageHash</code> — string</li></ul><p>Additionally, only for regular images:</p><ul><li><code>takenOnGrindr</code> — boolean or <code>null</code></li><li><code>createdAt</code> — number or <code>null</code></li></ul><h3 id="chatimage" tabindex="-1"><code>&quot;ChatImage&quot;</code> <a class="header-anchor" href="#chatimage" aria-label="Permalink to “&quot;ChatImage&quot;”">​</a></h3><ul><li><code>mediaId</code> — number</li><li><code>url</code> — string</li><li><code>expiresAt</code> — unix timestamp in milliseconds</li><li><code>takenOnGrindr</code> — boolean</li><li><code>createdTs</code> — number</li></ul><h3 id="expiringimage" tabindex="-1"><code>&quot;ExpiringImage&quot;</code> <a class="header-anchor" href="#expiringimage" aria-label="Permalink to “&quot;ExpiringImage&quot;”">​</a></h3><ul><li><em>everything from <a href="#image">&quot;Image&quot; message type</a></em></li><li><code>viewsRemaining</code> — number or <code>null</code></li></ul><h3 id="location" tabindex="-1"><code>&quot;Location&quot;</code> <a class="header-anchor" href="#location" aria-label="Permalink to “&quot;Location&quot;”">​</a></h3><ul><li><code>lat</code> — number</li><li><code>lon</code> — number</li></ul><h3 id="profilelink" tabindex="-1"><code>&quot;ProfileLink&quot;</code> <a class="header-anchor" href="#profilelink" aria-label="Permalink to “&quot;ProfileLink&quot;”">​</a></h3><p>Unknown, WIP</p><h3 id="profilephotoreply" tabindex="-1"><code>&quot;ProfilePhotoReply&quot;</code> <a class="header-anchor" href="#profilephotoreply" aria-label="Permalink to “&quot;ProfilePhotoReply&quot;”">​</a></h3><p>Unknown, WIP</p><ul><li><code>imageHash</code> — string</li><li><code>photoContentReply</code> — string</li></ul><h3 id="retract" tabindex="-1"><code>&quot;Retract&quot;</code> <a class="header-anchor" href="#retract" aria-label="Permalink to “&quot;Retract&quot;”">​</a></h3><p>Unknown, WIP</p><ul><li><code>targetMessageId</code> — string</li></ul><h3 id="text" tabindex="-1"><code>&quot;Text&quot;</code> <a class="header-anchor" href="#text" aria-label="Permalink to “&quot;Text&quot;”">​</a></h3><ul><li><code>text</code> — string</li></ul><h3 id="videocall" tabindex="-1"><code>&quot;VideoCall&quot;</code> <a class="header-anchor" href="#videocall" aria-label="Permalink to “&quot;VideoCall&quot;”">​</a></h3><p>WIP</p><p>Only for &quot;status&quot; messages:</p><ul><li><code>result</code> — string or <code>null</code>, appears to have the following values: <code>SUCCESSFUL</code>, <code>Duration:</code>, <code>Busy</code>, <code>BUSY</code>, <code>Cancelled</code>, <code>Declined</code>, <code>DECLINED</code>, <code>Missed</code>, <code>AB_Unsupported</code>, <code>No_Answer</code>, <code>UNANSWERED</code>, <code>Lite_Unsupport</code></li><li><code>videoCallDuration</code> — number or <code>null</code></li></ul><h3 id="unknown" tabindex="-1"><code>&quot;Unknown&quot;</code> <a class="header-anchor" href="#unknown" aria-label="Permalink to “&quot;Unknown&quot;”">​</a></h3><p>Empty type</p><h2 id="get-messages-in-a-conversation" tabindex="-1">Get messages in a conversation <a class="header-anchor" href="#get-messages-in-a-conversation" aria-label="Permalink to “Get messages in a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Invoking this endpoint does not <a href="#mark-messages-as-read-up-to-message-id">mark messages as read</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v5/chat/conversation/{conversationId}/message</span></span></code></pre></div><p>Query (optional):</p><ul><li><code>pageKey</code> — optional, return messages with IDs before specified value</li><li><code>profile</code> — boolean (<code>profile=true</code> | <code>profile=</code> + any other value), optional</li></ul><p>Response:</p><ul><li><code>lastReadTimestamp</code> — unix timestamp in milliseconds</li><li><code>messages</code> — array of <a href="#message">Message</a></li><li><code>metadata</code> — nested object <ul><li><code>translate</code> — boolean</li><li><code>hasSharedAlbums</code> — boolean</li><li><code>isInAList</code> — boolean</li></ul></li><li><code>profile</code> — object if <code>profile</code> query parameter is set to <code>true</code> or <code>null</code><ul><li><code>profileId</code> — long integer</li><li><code>name</code> — string, may be empty</li><li><code>mediaHash</code> — string or <code>null</code>, see <a href="/grindr-api/media/index#media">Media</a></li><li><code>onlineUntil</code> — unknown or <code>null</code></li><li><code>distance</code> — float or <code>null</code></li><li><code>showDistance</code> — boolean</li></ul></li></ul><h2 id="get-a-single-message-in-a-conversation" tabindex="-1">Get a single message in a conversation <a class="header-anchor" href="#get-a-single-message-in-a-conversation" aria-label="Permalink to “Get a single message in a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v4/chat/conversation/{conversationId}/message/{messageId}</span></span></code></pre></div><p>Response:</p><ul><li><code>message</code> — <a href="#message">Message</a></li></ul><h2 id="send-a-message-to-a-conversation" tabindex="-1">Send a message to a conversation <a class="header-anchor" href="#send-a-message-to-a-conversation" aria-label="Permalink to “Send a message to a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Please don&#39;t use this for spam. Be civil.</p><p>See also: <a href="/grindr-api/websocket/commands#send-a-message-to-a-conversation-via-ws">Send a message to a conversation via WS</a></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/message/send</span></span></code></pre></div><p>Body:</p><ul><li><code>type</code> — string, see <a href="#message-type">Message type</a></li><li><code>target</code> — nested object <ul><li><code>type</code> — <code>Direct</code>, <code>Group</code>, <code>HumanWingman</code></li><li><code>targetId</code> — integer</li></ul></li><li><code>body</code> — object with <a href="#message-contents">Message contents</a> or <code>null</code></li></ul><p>Additional body fields for <a href="/grindr-api/websocket/commands#send-a-message-to-a-conversation-via-ws">websocket</a> only:</p><ul><li><code>replyToMessageId</code> — string or <code>null</code>, optional</li></ul><p>When <code>replyToMessageId</code> is used in HTTP API appears to cause 400 Bad Request error.</p><p>Response:</p><p>HTTP status 201.</p><p><a href="#message">Message</a> object.</p><h2 id="unsend-a-message" tabindex="-1">Unsend a message <a class="header-anchor" href="#unsend-a-message" aria-label="Permalink to “Unsend a message”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Turns a message in chat into &quot;This message was unsent.&quot;</p><p>Repeated requests are completed without errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/message/unsend</span></span></code></pre></div><p>Body:</p><ul><li><code>conversationId</code> — string</li><li><code>messageId</code> — string, must be sent by you</li></ul><p>Response:</p><p>Empty.</p><p>Errors:</p><ul><li>500 Internal Error if conversation or message was not found or if it wasn&#39;t sent by you</li></ul><h2 id="delete-a-message" tabindex="-1">Delete a message <a class="header-anchor" href="#delete-a-message" aria-label="Permalink to “Delete a message”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Deletes a message on your side. Does not delete message for other chat participant.</p><p>Repeated requests are completed without errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/message/delete</span></span></code></pre></div><p>Body:</p><ul><li><code>conversationId</code> — string</li><li><code>messageId</code> — string</li></ul><p>Response:</p><p>Empty.</p><p>Errors:</p><ul><li>500 Internal Error if conversation or message was not found</li></ul><h2 id="send-typing-indicator" tabindex="-1">Send typing indicator <a class="header-anchor" href="#send-typing-indicator" aria-label="Permalink to “Send typing indicator”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>WIP, does not seem to work.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chatstatus/typing</span></span></code></pre></div><p>Body:</p><ul><li><code>conversationId</code> — string</li><li><code>status</code> — either <code>&quot;Typing&quot;</code> or <code>&quot;Cleared&quot;</code></li></ul><p>Response:</p><p>Empty.</p><p>Errors:</p><ul><li>403 Action not permitted if conversation not found</li></ul><h2 id="react-to-a-message" tabindex="-1">React to a message <a class="header-anchor" href="#react-to-a-message" aria-label="Permalink to “React to a message”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>There is no discovered way to undo the reaction as of yet.</p><p>Repeated requests are completed without errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/message/reaction</span></span></code></pre></div><p>Body:</p><ul><li><code>conversationId</code> — string</li><li><code>messageId</code> — string</li><li><code>reactionType</code> — integer, (<code>1</code> is &quot;🔥&quot;)</li></ul><p>Response:</p><p>Empty.</p><p>Errors:</p><ul><li>500 Internal Error if conversation or message was not found</li></ul>',134)])])}const g=o(t,[["render",d]]);export{h as __pageData,g as default};
